Prolog:
sOutputFile = Trim(pOutputFile);
sLocaleCsv = Upper(Trim(pLocaleCsv));
sIncludeEmpty = Upper(Trim(pIncludeEmpty));
If(sOutputFile @= ''); sOutputFile = 'docs/status/IMF_Text_Export.csv'; EndIf;
If(sIncludeEmpty @= ''); sIncludeEmpty = 'N'; EndIf;
ASCIIOutput(sOutputFile, 'TextKey', 'Domain', 'Locale', 'Text', 'Status', 'Owner', 'LastUpdatedBy', 'LastUpdatedAt');
If(CubeExists('IMF.C.Text') = 0 % DimensionExists('IMF.D.TextKey') = 0 % DimensionExists('IMF.D.Language') = 0);
  ASCIIOutput(sOutputFile, '', '', '', '', 'ERROR', '', '', 'Required language control objects are not deployed.');
Else;
  nKeyCount = Dimsiz('IMF.D.TextKey');
  nLocaleCount = Dimsiz('IMF.D.Language');
  nKeyIndex = 1;
  While(nKeyIndex <= nKeyCount);
    sTextKey = DimNm('IMF.D.TextKey', nKeyIndex);
    If(sTextKey @<> 'All Text Keys');
      sDomain = Trim(AttrS('IMF.D.TextKey', sTextKey, 'Domain'));
      If(SubSt(sTextKey, 1, 6) @<> 'IMF.P.' & SubSt(sTextKey, 1, 6) @<> 'IMF.C.' & SubSt(sTextKey, 1, 6) @<> 'IMF.D.');
        nLocaleIndex = 1;
        While(nLocaleIndex <= nLocaleCount);
          sLocale = DimNm('IMF.D.Language', nLocaleIndex);
          If(sLocale @<> 'All Languages');
            If(sLocaleCsv @= '' % Scan(Upper(sLocale), sLocaleCsv) > 0);
              sText = CellGetS('IMF.C.Text', sTextKey, sLocale, 'Text');
              sCellStatus = CellGetS('IMF.C.Text', sTextKey, sLocale, 'Status');
              sOwner = CellGetS('IMF.C.Text', sTextKey, sLocale, 'Owner');
              sUpdatedBy = CellGetS('IMF.C.Text', sTextKey, sLocale, 'LastUpdatedBy');
              sUpdatedAt = CellGetS('IMF.C.Text', sTextKey, sLocale, 'LastUpdatedAt');
              If(sIncludeEmpty @= 'Y' % Trim(sText) @<> '');
                ASCIIOutput(sOutputFile, sTextKey, sDomain, sLocale, sText, sCellStatus, sOwner, sUpdatedBy, sUpdatedAt);
              EndIf;
            EndIf;
          EndIf;
          nLocaleIndex = nLocaleIndex + 1;
        End;
      EndIf;
    EndIf;
    nKeyIndex = nKeyIndex + 1;
  End;
EndIf;
